class Solution:
    def findCheapestPrice(self, n: int, flights: List[List[int]], src: int, dst: int, k: int) -> int:
        INF = 10**9
        dist = [INF] * n
        dist[src] = 0
        for _ in range(k + 1):
            nd = dist[:]
            for u, v, w in flights:
                if dist[u] + w < nd[v]:
                    nd[v] = dist[u] + w
            dist = nd
        return dist[dst] if dist[dst] < INF else -1

