class Solution {
public:
    int findCheapestPrice(int n, vector<vector<int>>& f, int src, int dst, int k) {
        const int INF=1e9;
        vector<int> dist(n,INF); dist[src]=0;
        for(int s=0;s<=k;s++){
            vector<int> nd=dist;
            for(auto& e:f){
                int u=e[0],v=e[1],w=e[2];
                if(dist[u]!=INF) nd[v]=min(nd[v],dist[u]+w);
            }
            dist=move(nd);
        }
        return dist[dst]==INF?-1:dist[dst];
    }
};

